    private void createBtnActionPerformed(java.awt.event.ActionEvent evt) {//GEN-FIRST:event_createBtnActionPerformed
            Sound s = new Sound();
            String username = textField_Username.getText();
            String Name=textField_Name.getText();
            String passwordSave = password;
            String inputrole = roleCB.getSelectedItem().toString();
            String NID= "";
            BankFunction BF = new BankFunction();
            if(textField_Username.getText().isEmpty() || textField_Name.getText().isEmpty() || textField_Password.getText().isEmpty()){
                JOptionPane.showMessageDialog(this,"Please ensure that all the details are enter correctly!");
            }

                String databaseURL ="jdbc:ucanaccess://src\\database\\Userdb.accdb";
                //String databaseURL = "jdbc:ucanaccess://C:\\Users\\User\\Documents\\NetBeansProjects\\UNION BANK SYSTEM\\src\\database\\Userdb.accdb";
            try (Connection connection = DriverManager.getConnection(databaseURL)) {
                System.out.println("connected");
                 if(BF.CheckUsername(connection,username)&&BF.CheckName(connection,Name)){
                     JOptionPane.showMessageDialog(this,"The username and name is already exist!");
                 }else{
                     
                     
                    String sql = "SELECT Max(accountNumber) FROM User";
                    Statement statment=connection.createStatement();
                    ResultSet maxID= statment.executeQuery(sql);
                    if (maxID.next()) {
                        int maxIdValue = maxID.getInt(1);
                        int id = maxIdValue+1;
                        NID=id+"";
                    }
                    
                    String regUserSql ="INSERT INTO User(accountNumber, UserName,Name,password, role) values(?,?,?,?,?)";    
                    try (PreparedStatement registerValue = connection.prepareStatement(regUserSql)) {

                    registerValue.setString(1,NID);
                    registerValue.setString(2,username);
                    registerValue.setString(3,Name);
                    registerValue.setString(4,passwordSave);
                    registerValue.setString(5,inputrole);
                    registerValue.executeUpdate();
                    JOptionPane.showMessageDialog(this,"Please confirm your username and password:\nUsername: "+username+"\nName:"+Name+"\nPassword: "+password);
                    if(inputrole.equals("User") ){
                       String regAccSql ="INSERT INTO Account(accountNumber) values(?)"; 
                            try (PreparedStatement registerAcc = connection.prepareStatement(regAccSql)) {
                            registerAcc.setString(1,NID);
                            registerAcc.executeUpdate();

                            }catch (Exception e){
                            System.err.println("Got an exception!");

                            e.printStackTrace();

                            System.out.println(e); 
                            }     
                        } 
                    }catch (Exception e){
                System.err.println("Got an exception!");
                e.printStackTrace();
                System.out.println(e); 
                }
                 }
                
            }catch (Exception e){
                System.err.println("Got an exception!");
                e.printStackTrace();
                System.out.println(e); 
        }
    }//GEN-LAST:event_createBtnActionPerformed

    private void checkBtnActionPerformed(java.awt.event.ActionEvent evt) {//GEN-FIRST:event_checkBtnActionPerformed
                Sound s = new Sound();
                s.OptionSound();
                String username = textField_Username.getText();
                String name = textField_Name.getText();
                String password = textField_Password.getText();
                String us,pw,nm;        
                String databaseURL = "jdbc:ucanaccess://src\\database\\Userdb.accdb";
         
                try (Connection connection = DriverManager.getConnection(databaseURL)) {
                System.out.println("connected");
                String sql = "select * from User";
                Statement statment=connection.createStatement();
                ResultSet result = statment.executeQuery(sql);
                
                while(result.next()){
                    
                     us=result.getString("UserName");
                     nm=result.getString("Name");
                     pw = result.getString("password");
                    
                    System.out.println(us+" "+pw);
                   if(username.equals(us) || name.equals(nm)){
                       s.ErrorSound();
                       JOptionPane.showMessageDialog(this,"The data is already exist. \nPlease try again!" );
                   }         
                }
                 connection.close();  
                }catch (Exception e){
                System.err.println("Got an exception!");
              
                e.printStackTrace();
                
                System.out.println(e); 
                }    
    }//GEN-LAST:event_checkBtnActionPerformed

